mapper.select:
SELECT a.id, a.entire_no, a.device_id, a.device_name, a.prison_id, p.name prison_name, a.content, a.type, a.alarm_time, a.suggestions, a.processing_status, a.resolution_time, a.blocked, a.create_by, a.create_time, a.update_by, a.update_time, a.is_deleted, b.name building_name, b.id building_id, f.id floor_id, f.floor_name FROM t_alarm a left join t_device d on d.id = a.device_id left join t_floor f on f.id = d.floor_id left join t_building b on b.id = f.building_id left join t_prison p on p.id = b.prison_id
a.is_deleted = 0
AND p.dept_id = #{queryParams.provinceId}
AND a.prison_id = #{queryParams.prisonId}
AND b.id = #{queryParams.buildingId}
AND ( a.device_name LIKE CONCAT('%',#{queryParams.deviceName},'%') )
AND a.type = #{queryParams.type}
AND a.alarm_time >= #{queryParams.startDate}
AND a.alarm_time <= #{queryParams.endDate}
AND a.processing_status = #{queryParams.processingStatus}
AND a.processing_status = #{queryParams.processingStatus}
AND a.blocked = #{queryParams.blocked}
ORDER BY a.alarm_time DESC

SELECT
entire_no,
device_name,
prison_name,
content,
alarm_time,
suggestions,
processing_status,
resolution_time
FROM
t_alarm

    is_deleted = 0

        AND (
        device_name LIKE CONCAT('%',#{queryParams.deviceName},'%')
        )


        AND type = #{queryParams.type}


        AND alarm_time >= #{queryParams.startDate}


        AND alarm_time <= #{queryParams.endDate}


        AND processing_status = #{queryParams.processingStatus}


        AND processing_status = #{queryParams.processingStatus}


        AND blocked = #{queryParams.blocked}


ORDER BY alarm_time DESC
